// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Check if the Ollama server is running
	// (GET /)
	GetHealth(c *gin.Context)
	// Check if the Ollama server is running
	// (HEAD /)
	CheckHealth(c *gin.Context)
	// Check if a blob exists
	// (HEAD /api/blobs/{digest})
	HeadBlob(c *gin.Context, digest string)
	// Create a blob from a file
	// (POST /api/blobs/{digest})
	CreateBlob(c *gin.Context, digest string)
	// Generate the next message in a chat with a model
	// (POST /api/chat)
	GenerateChat(c *gin.Context)
	// Copy a model to a new name
	// (POST /api/copy)
	CopyModel(c *gin.Context)
	// Create a model from a Modelfile
	// (POST /api/create)
	CreateModel(c *gin.Context)
	// Delete a model and its associated layers
	// (DELETE /api/delete)
	DeleteModel(c *gin.Context)
	// Generate embeddings from a model
	// (POST /api/embed)
	GenerateEmbedding(c *gin.Context)
	// Generate a single embedding (legacy endpoint)
	// (POST /api/embeddings)
	GenerateEmbeddingLegacy(c *gin.Context)
	// Get model recommendations
	// (GET /api/experimental/model-recommendations)
	ModelRecommendationsExperimental(c *gin.Context)
	// Proxy a web fetch request to the cloud
	// (POST /api/experimental/web_fetch)
	WebFetchExperimental(c *gin.Context)
	// Proxy a web search request to the cloud
	// (POST /api/experimental/web_search)
	WebSearchExperimental(c *gin.Context)
	// Generate a response from a model given a prompt
	// (POST /api/generate)
	GenerateCompletion(c *gin.Context)
	// Get information about the currently signed-in user
	// (POST /api/me)
	Whoami(c *gin.Context)
	// List models that are currently loaded in memory
	// (GET /api/ps)
	ListRunningModels(c *gin.Context)
	// Download a model from a registry
	// (POST /api/pull)
	PullModel(c *gin.Context)
	// Upload a model to a registry
	// (POST /api/push)
	PushModel(c *gin.Context)
	// Show information about a model including details, modelfile, license, etc.
	// (POST /api/show)
	ShowModel(c *gin.Context)
	// Sign out the current user by disconnecting their key
	// (POST /api/signout)
	Signout(c *gin.Context)
	// Get the server status including cloud information
	// (GET /api/status)
	GetStatus(c *gin.Context)
	// List models that are available locally
	// (GET /api/tags)
	ListLocalModels(c *gin.Context)
	// Check if model list is available
	// (HEAD /api/tags)
	HeadLocalModels(c *gin.Context)
	// Sign out (deprecated)
	// (DELETE /api/user/keys/{encodedKey})
	SignoutDeprecated(c *gin.Context, encodedKey string)
	// Get the server version
	// (GET /api/version)
	GetVersion(c *gin.Context)
	// Get the server version
	// (HEAD /api/version)
	HeadVersion(c *gin.Context)
	// OpenAI-compatible audio transcriptions endpoint
	// (POST /v1/audio/transcriptions)
	OpenaiAudioTranscriptions(c *gin.Context)
	// OpenAI-compatible chat completions endpoint
	// (POST /v1/chat/completions)
	OpenaiChatCompletions(c *gin.Context)
	// OpenAI-compatible text completions endpoint
	// (POST /v1/completions)
	OpenaiCompletions(c *gin.Context)
	// OpenAI-compatible embeddings endpoint
	// (POST /v1/embeddings)
	OpenaiEmbeddings(c *gin.Context)
	// OpenAI-compatible image edits endpoint
	// (POST /v1/images/edits)
	OpenaiImageEdits(c *gin.Context)
	// OpenAI-compatible image generations endpoint
	// (POST /v1/images/generations)
	OpenaiImageGenerations(c *gin.Context)
	// Anthropic-compatible messages endpoint
	// (POST /v1/messages)
	AnthropicMessages(c *gin.Context)
	// OpenAI-compatible list models endpoint
	// (GET /v1/models)
	OpenaiListModels(c *gin.Context)
	// OpenAI-compatible retrieve model endpoint
	// (GET /v1/models/{model})
	OpenaiRetrieveModel(c *gin.Context, model string)
	// OpenAI Responses API endpoint
	// (POST /v1/responses)
	OpenaiResponses(c *gin.Context)
}

